def login_required(f):
    """Decorator to require authentication."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect('/saml/login')
        
        # Check session expiry
        if 'session_expires' in session:
            if datetime.utcnow().isoformat() > session['session_expires']:
                session.clear()
                return redirect('/saml/login')
        
        return f(*args, **kwargs)
    return decorated_function


@app.route('/saml/login')
def saml_login():
    """Initiate SAML authentication by redirecting to IdP."""
    request_id = '_' + os.urandom(16).hex()
    
    saml_request = f"""<samlp:AuthnRequest
        xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
        xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
        ID="{request_id}"
        Version="2.0"
        IssueInstant="{datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')}"
        Destination="{SP_CONFIG['idp_sso_url']}"
        AssertionConsumerServiceURL="{SP_CONFIG['acs_url']}"
        ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
        <saml:Issuer>{SP_CONFIG['entity_id']}</saml:Issuer>
        <samlp:NameIDPolicy
            Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
            AllowCreate="false"/>
    </samlp:AuthnRequest>"""
    
    encoded_request = base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')
    
    # Store request ID in session for InResponseTo validation
    session['saml_request_id'] = request_id
    
    return redirect(f"{SP_CONFIG['idp_sso_url']}?SAMLRequest={encoded_request}")


@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    """Assertion Consumer Service — process SAML Response from IdP."""
    saml_response = request.form.get('SAMLResponse')
    if not saml_response:
        abort(400, description="Missing SAMLResponse parameter.")
    
    try:
        user_data = parse_saml_response(saml_response)
    except NotImplementedError as e:
        # In development, log and provide guidance
        app.logger.error(f"SAML signature verification not implemented: {e}")
        abort(500, description="SAML signature verification not configured.")
    except ValueError as e:
        app.logger.warning(f"SAML response validation failed: {e}")
        abort(403, description="SAML authentication failed.")
    except Exception as e:
        app.logger.error(f"Unexpected error processing SAML response: {e}")
        abort(500, description="Internal error processing SAML response.")
    
    # Create user session
    session.clear()
    session['user'] = {
        'name_id': user_data['name_id'],
        'name_id_format': user_data['name_id_format'],
        'attributes': user_data['attributes'],
        'authenticated_at': datetime.utcnow().isoformat(),
    }
    
    if user_data.get('session_index'):
        session['saml_session_index'] = user_data['session_index']
    
    # Set session expiry (default 8 hours)
    session['session_expires'] = (datetime.utcnow() + timedelta(hours=8)).isoformat()
    
    session.permanent = True
    app.permanent_session_lifetime = timedelta(hours=8)
    
    return redirect('/dashboard')


@app.route('/dashboard')
@login_required
def dashboard():
    """Protected dashboard page."""
    user = session['user']
    return jsonify({
        'message': 'Authenticated via SAML SSO',
        'user': {
            'name_id': user['name_id'],
            'attributes': user['attributes'],
            'authenticated_at': user['authenticated_at'],
        }
    })


@app.route('/saml/logout')
@login_required
def saml_logout():
    """Logout and clear session."""
    session.clear()
    return redirect('/')


@app.route('/saml/metadata')
def saml_metadata():
    """Serve SP metadata."""
    metadata = f"""<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{SP_CONFIG['entity_id']}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="true"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{SP_CONFIG['acs_url']}"
            index="0"
            isDefault="true"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>"""
    
    return metadata, 200, {'Content-Type': 'application/xml'}


