def index():
    """Home page."""
    if 'user' in session:
        return redirect('/dashboard')
    return jsonify({
        'message': 'SAML SP - Enterprise SSO Integration',
        'login_url': '/saml/login',
        'metadata_url': '/saml/metadata',
    })


